// Helper to generate MRZ (Machine Readable Zone) simulation
const generateMRZ = (userData: UserData) => {
  const nameParts = userData.fullName.split(' ');
  const lastName = nameParts[nameParts.length - 1]?.toUpperCase() || 'UNKNOWN';
  const firstName = nameParts[0]?.toUpperCase() || 'UNKNOWN';
  const id = userData.nationalId.padEnd(14, '<');
  return {
    line1: `IDSDN${lastName}<<${firstName}<<<<<<<<<<<<<<<<<`,
    line2: `${id}SDN${userData.birthDate.replace(/-/g, '').slice(2)}<M<<<<<<<<<<<`
  };
};

