                          <div className="bg-green-600 h-2.5 rounded-full" style={{ width: `${verificationResult.confidence}%` }}></div>
                        </div>
                        <p className="text-xs text-green-600 font-bold mb-6">نسبة التطابق: {verificationResult.confidence}%</p>

